<main class="main-content"><section class="sales-shell"><div class="sales-hero"><div><div class="sales-kicker">Follow-up Discipline</div><h1>Edit Follow-up</h1><p>Perbarui hasil follow-up dan next action.</p></div><a class="sales-btn secondary" href="<?= app_url('sales/followups'); ?>"><i class="bi bi-arrow-left"></i> Back</a></div><div class="sales-grid"><article class="sales-card span-7"><form class="sales-form" action="<?= app_url('sales/followups/update/'.(int)$followup['id']); ?>" method="POST"><div class="sales-field"><label>Lead</label><select name="lead_id"><option value="">Tanpa lead</option><?php foreach($leads as $l): ?><option value="<?= (int)$l['id']; ?>" <?= (int)$followup['lead_id']===(int)$l['id']?'selected':''; ?>><?= htmlspecialchars($l['company_name']); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Opportunity</label><select name="opportunity_id"><option value="">Tanpa opportunity</option><?php foreach($opportunities as $o): ?><option value="<?= (int)$o['id']; ?>" <?= (int)$followup['opportunity_id']===(int)$o['id']?'selected':''; ?>><?= htmlspecialchars($o['title']); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Type</label><select name="activity_type"><?php foreach(['call','meeting','email','whatsapp','document_review'] as $t): ?><option value="<?= $t; ?>" <?= $followup['activity_type']===$t?'selected':''; ?>><?= sales_label($t); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Activity Date</label><input name="activity_date" type="date" value="<?= htmlspecialchars($followup['activity_date']); ?>" required></div><div class="sales-field full"><label>Result</label><input name="result" value="<?= htmlspecialchars($followup['result']); ?>"></div><div class="sales-field full"><label>Next Action</label><input name="next_action" value="<?= htmlspecialchars($followup['next_action']); ?>"></div><div class="sales-field"><label>Next Follow-up</label><input name="next_followup_date" type="date" value="<?= htmlspecialchars($followup['next_followup_date'] ?? ''); ?>"></div><div class="sales-field"><label>Assigned</label><select name="assigned_user_id"><option value="">Unassigned</option><?php foreach($users as $u): ?><option value="<?= (int)$u['id']; ?>" <?= (int)$followup['assigned_user_id']===(int)$u['id']?'selected':''; ?>><?= htmlspecialchars($u['full_name'] ?: $u['username']); ?></option><?php endforeach; ?></select></div><div class="sales-field full"><label>Notes</label><textarea name="notes"><?= htmlspecialchars($followup['notes']); ?></textarea></div><div class="sales-field full"><button class="sales-btn" type="submit"><i class="bi bi-save"></i> Update Follow-up</button></div></form></article></div></section></main><footer class="app-footer"><span>&copy; <?= date('Y'); ?> NovaTrack Riksa</span></footer></body></html>
